using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class ChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", -10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 50.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 50.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_VeryLargeAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999_999.99m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallValidAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class RefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrEmpty(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_InvalidChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_DuplicateRefund_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        var duplicate = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(duplicate.Success);
    }

    [TestMethod]
